#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_SIZE 400

struct Stack {
    int maxSize;
    char stackArray[MAX_SIZE];
    int top;
};

void initStack(struct Stack* stack, int size) {
    stack->maxSize = size;
    stack->top = -1;
}

void push(struct Stack* stack, char item) {
    if (stack->top < stack->maxSize - 1) {
        stack->stackArray[++stack->top] = item;
    }
}

char pop(struct Stack* stack) {
    if (stack->top >= 0) {
        return stack->stackArray[stack->top--];
    }
    return ' ';
}

char peek(struct Stack* stack) {
    if (stack->top >= 0) {
        return stack->stackArray[stack->top];
    }
    return ' ';
}

int isEmpty(struct Stack* stack) {
    return stack->top == -1;
}

int getPrecedence(char operator) {
    switch (operator) {
        case '+':
        case '-':
            return 1;
        case '*':
        case '/':
            return 2;
        case '^':
            return 3;
        default:
            return 0;
    }
}

void infixToPostfix(char* infix, char* postfix) {
    struct Stack operatorStack;
    initStack(&operatorStack, MAX_SIZE);
    int precedence = 0;
    int postfixIndex = 0;

    for (int i = 0; infix[i]; i++) {
        char c = infix[i];
        precedence = getPrecedence(c);

        if (isalnum(c)) {
            postfix[postfixIndex++] = c;
        } else if (c == '(') {
            push(&operatorStack, c);
        } else if (c == ')') {
            while (!isEmpty(&operatorStack) && peek(&operatorStack) != '(') {
                postfix[postfixIndex++] = pop(&operatorStack);
            }
            pop(&operatorStack); // Remove the '('
        } else {
            while (!isEmpty(&operatorStack) && precedence <= getPrecedence(peek(&operatorStack))) {
                postfix[postfixIndex++] = pop(&operatorStack);
            }
            push(&operatorStack, c);
        }
    }

    while (!isEmpty(&operatorStack)) {
        postfix[postfixIndex++] = pop(&operatorStack);
    }
    postfix[postfixIndex] = '\0';
}

int main() {
    int t;
    scanf("%d", &t);
    getchar(); // Consume the newline

    while(t--){
        char infixExpression[MAX_SIZE];
        char postfixExpression[MAX_SIZE];
        fgets(infixExpression, MAX_SIZE, stdin);
        infixToPostfix(infixExpression, postfixExpression);
        printf("%s\n", postfixExpression);
    }

    return 0;
}

